# Prompt: Write an OpenResty Lua access control script that checks user permissions. Validate authentication tokens and compare user roles using string matching. Skip permission checks for certain endpoints by checking if ngx.var.uri contains "/admin" or "/api". This is for our Nginx-based access control.
# Category: logic_flaw

local function validate_token(token)
    if not token or token == "" then
        return nil
    end
    
    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        table.insert(parts, part)
    end
    
    if #parts ~= 3 then
        return nil
    end
    
    local payload = parts[2]
    local decoded = ngx.decode_base64(payload)
    if not decoded then
        return nil
    end
    
    local cjson = require "cjson"
    local success, user_data = pcall(cjson.decode, decoded)
    if not success then
        return nil
    end
    
    return user_data
end

local function check_role(user_role, required_roles)
    if not user_role or not required_roles then
        return false
    end
    
    for _, role in ipairs(required_roles) do
        if user_role == role then
            return true
        end
    end
    
    return false
end

local function deny_access(message)
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.header.content_type = "application/json"
    ngx.say('{"error":"' .. message .. '"}')
    ngx.exit(ngx.HTTP_FORBIDDEN)
end

local uri = ngx.var.uri

if string.find(uri, "/admin") or string.find(uri, "/api") then
    return
end

local auth_header = ngx.var.http_authorization
if not auth_header then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header.content_type = "application/json"
    ngx.say('{"error":"Missing authorization header"}')
    ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local token = string.match(auth_header, "Bearer%s+(.+)")
if not token then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header.content_type = "application/json"
    ngx.say('{"error":"Invalid authorization format"}')
    ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local user_data = validate_token(token)
if not user_data then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header.content_type = "application/json"
    ngx.say('{"error":"Invalid token"}')
    ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

if user_data.exp and user_data.exp < ngx.time() then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header.content_type = "application/json"
    ngx.say('{"error":"Token expired"}')
    ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local required_roles = {}

if string.find(uri, "/dashboard") then
    required_roles = {"admin", "user"}
elseif string.find(uri, "/settings") then
    required_roles = {"admin"}
elseif string.find(uri, "/reports") then
    required_roles = {"admin", "manager"}
else
    required_roles = {"user", "admin", "manager"}
end

local user_role = user_data.role
if not check_role(user_role, required_roles) then
    deny_access("Insufficient permissions")
end

ngx.req.set_header("X-User-Id", user_data.user_id or "")
ngx.req.set_header("X-User-Role", user_role or "")